import{c as a,Q as e,j as r,m as l}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse(`{"title":"The Multi-Agent Approach: How Claude Code's Creator Actually Uses the Tool","description":"","frontmatter":{"url":"https://vatchechamlian.com/orchestrating-agents-claude.html","title":"The Multi-Agent Approach: How Claude Code's Creator Actually Uses the Tool","type":"article"},"headers":[],"relativePath":"research/ai-articles/14-vatchechamlian-multi-agent-boris.md","filePath":"research/ai-articles/14-vatchechamlian-multi-agent-boris.md","lastUpdated":1779796674000}`),o={name:"research/ai-articles/14-vatchechamlian-multi-agent-boris.md"};function n(s,t,i,h,c,g){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="the-multi-agent-approach-how-claude-code-s-creator-actually-uses-the-tool" tabindex="-1">The Multi-Agent Approach: How Claude Code&#39;s Creator Actually Uses the Tool <a class="header-anchor" href="#the-multi-agent-approach-how-claude-code-s-creator-actually-uses-the-tool" aria-label="Permalink to &quot;The Multi-Agent Approach: How Claude Code&#39;s Creator Actually Uses the Tool&quot;">​</a></h1><p><strong>原始 URL</strong>: <a href="https://vatchechamlian.com/orchestrating-agents-claude.html" target="_blank" rel="noreferrer">https://vatchechamlian.com/orchestrating-agents-claude.html</a></p><p><strong>作者</strong>: Vatché Chamlian<br><strong>發佈日期</strong>: 2026 年 1 月 6 日<br><strong>來源</strong>: vatchechamlian.com</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>本文探討 Boris Cherny 採用的多 agent 方法論，重點在於「同時運行多個 Claude agent 而非依賴單一聊天機器人」。核心概念是「協調多個 AI agent 平行工作，各自執行任務，而你像指揮官在他們之間切換」。該方法透過結構化協調、團隊知識庫、計畫模式與驗證迴圈，顯著改善代碼品質與開發速度。</p><h3 id="多-agent-協調核心" tabindex="-1">多 Agent 協調核心 <a class="header-anchor" href="#多-agent-協調核心" aria-label="Permalink to &quot;多 Agent 協調核心&quot;">​</a></h3><p><strong>並行處理</strong> Boris Cherny 同時操作 5-15 個 Claude 實例，經由終端標籤與瀏覽器會話隔離。使用 iTerm2 通知在 agents 需要輸入時警告他。</p><p><strong>團隊知識庫</strong> 共享 CLAUDE.md 檔案記錄專案模式、開發工作流程與常見錯誤。此檔案隨時間形成「複合知識庫」，團隊文件化教訓時改善。</p><p><strong>計畫模式優先</strong> 工作流程強調在實作前迭代方法，使用專用「計畫模式」在執行前精化策略。</p><p><strong>驗證迴圈</strong> 品質改善依賴「給 Claude 一個驗證其工作的方法」，經由自動化測試與瀏覽器驗證。此為「品質最重要單一因素」。</p><p><strong>自動化工具</strong> 斜線命令、subagents 與 hooks 減少重複任務，讓 Claude 在常見開發工作流程中更自主工作。</p><hr><h2 id="關鍵實踐" tabindex="-1">關鍵實踐 <a class="header-anchor" href="#關鍵實踐" aria-label="Permalink to &quot;關鍵實踐&quot;">​</a></h2><p><strong>上下文管理與知識持久化</strong></p><ul><li>跨會話維護 CLAUDE.md 記錄模式與錯誤</li><li>分離多個 Claude 實例以保持每個會話乾淨</li><li>動態調整 agent 數量基於任務複雜度</li></ul><p><strong>指揮官模式（Conductor Pattern）</strong> 單人開發者或小團隊成員扮演指揮官，協調多個 agent 執行獨立任務：</p><ul><li>Agent 1: 核心功能開發</li><li>Agent 2: 測試自動化</li><li>Agent 3: 文件化</li><li>Agent 4-5: 平行 refactoring/探索</li></ul><p><strong>品質保證機制</strong></p><ul><li>自動化測試作為驗證基礎</li><li>瀏覽器檢驗進行前端驗證</li><li>代碼審查在多 agent 輸出合併前執行</li></ul><hr><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><blockquote><p>「給 Claude 一個驗證其工作的方法」是品質最重要單一因素</p></blockquote><p><strong>並行 Agent 規模</strong>: 5-15 個 Claude 實例同時運行<br><strong>知識庫</strong>: 共享 CLAUDE.md 隨時間形成複合知識庫<br><strong>協調工具</strong>: iTerm2 通知、終端標籤、git worktrees 隔離<br><strong>團隊知識</strong>: 文件化錯誤與模式形成可重複框架</p><hr><h2 id="工作流程特色" tabindex="-1">工作流程特色 <a class="header-anchor" href="#工作流程特色" aria-label="Permalink to &quot;工作流程特色&quot;">​</a></h2><p>多 agent 方法相比單一 agent 的主要優勢：</p><ul><li>平行執行加速開發（5-15x 會話數取決於任務複雜度）</li><li>知識累積保障長期效能</li><li>計畫優先策略減少錯誤</li><li>驗證迴圈確保品質</li></ul><p>此方法論適用於個人開發者與團隊，展示了如何將 Claude Code 從單一工具擴展至協調多 agent 系統。</p>',29)])])}const p=a(o,[["render",n]]);export{d as __pageData,p as default};
